text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표 시점은 금요일 15:00 KST로 정했다.",
        "condition": "smoke test가 통과해야 한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수정 대상인 `smoke-theme-pack.mjs`에서 packageName 불일치를 무시하도록 바꾸자.",
        "result": "거절됨"
      },
      {
        "proposal": "수요일 공개 릴리스를 목표로 하자.",
        "result": "최종 결정으로 채택되지 않음"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스를 내부 stretch goal로 삼는다.",
        "status": "내부 목표로만 언급됨"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토하자는 제안이 있었지만, owner는 정해지지 않았다."
      },
      {
        "item": "Hara의 tarball 경로 확인은 Minjun의 smoke 결과 게시 이후로만 연결되었고, 정확한 마감 시각은 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage note를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 올린 뒤 generated tarball path를 확인한다.",
      "due": "Minjun의 smoke 결과 게시 후",
      "status": "confirmed",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 smoke test 결과를 확인한다.",
      "smoke 통과 여부를 기준으로 금요일 15:00 KST 공개 릴리스 가능성을 재확인한다.",
      "tarball 경로가 올바른지 확인한다.",
      "README 설치 단계 검토가 필요한지 확인하되, owner와 시점은 새로 정하지 않는다.",
      "최종 릴리스 승인 권한과 내부 stretch goal의 릴리스 노트 반영 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너명",
      "예산 정보",
      "보안 사고 여부",
      "운영 장애 여부",
      "법무 승인 요구사항",
      "결정되지 않은 owner",
      "정해지지 않은 deadline",
      "기록에 없는 추가 원인, 합의, 책임자"
    ]
  },
  "non_invention_rules": [
    "fixture에 명시된 사실만 사용한다.",
    "customer, budget, security, outage, legal facts를 추가로 만들지 않는다.",
    "owner와 deadline은 확인된 경우에만 쓴다.",
    "결정된 사항과 거절된 제안, 내부 stretch goal, 리스크, open question을 섞지 않는다.",
    "불명확한 내용은 추정하지 말고 미확정으로 둔다."
  ]
}
